import{_ as l,o as a,c as s,ai as n}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"工作区记忆研究","description":"","frontmatter":{"read_when":["设计超越每日 Markdown 日志的工作区记忆（~/.opensoul/workspace）",{"Deciding":"standalone CLI vs deep OpenSoul integration"},"添加离线回忆 + 反思（retain/recall/reflect）"],"summary":"研究笔记：Clawd 工作区的离线记忆系统（Markdown 作为数据源 + 派生索引）","title":"工作区记忆研究","x-i18n":{"generated_at":"2026-02-03T10:06:14Z","model":"claude-opus-4-5","provider":"pi","source_hash":"1753c8ee6284999fab4a94ff5fae7421c85233699c9d3088453d0c2133ac0feb","source_path":"experiments/research/memory.md","workflow":15}},"headers":[],"relativePath":"zh-CN/experiments/research/memory.md","filePath":"zh-CN/experiments/research/memory.md","lastUpdated":1771906665000}'),i={name:"zh-CN/experiments/research/memory.md"};function o(t,e,r,c,p,d){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="工作区记忆-v2-离线-研究笔记" tabindex="-1"><a class="header-anchor" href="#工作区记忆-v2-离线-研究笔记">#</a> 工作区记忆 v2（离线）：研究笔记</h1><p>目标：Clawd 风格的工作区（<code>agents.defaults.workspace</code>，默认 <code>~/.opensoul/workspace</code>），其中&quot;记忆&quot;以每天一个 Markdown 文件（<code>memory/YYYY-MM-DD.md</code>）加上一小组稳定文件（例如 <code>memory.md</code>、<code>SOUL.md</code>）的形式存储。</p><p>本文档提出一种<strong>离线优先</strong>的记忆架构，保持 Markdown 作为规范的、可审查的数据源，但通过派生索引添加<strong>结构化回忆</strong>（搜索、实体摘要、置信度更新）。</p><h2 id="为什么要改变" tabindex="-1"><a class="header-anchor" href="#为什么要改变">#</a> 为什么要改变？</h2><p>当前设置（每天一个文件）非常适合：</p><ul><li>&quot;仅追加&quot;式日志记录</li><li>人工编辑</li><li>git 支持的持久性 + 可审计性</li><li>低摩擦捕获（&quot;直接写下来&quot;）</li></ul><p>但它在以下方面较弱：</p><ul><li>高召回率检索（&quot;我们对 X 做了什么决定？&quot;、&quot;上次我们尝试 Y 时？&quot;）</li><li>以实体为中心的答案（&quot;告诉我关于 Alice / The Castle / warelay 的信息&quot;）而无需重读多个文件</li><li>观点/偏好稳定性（以及变化时的证据）</li><li>时间约束（&quot;2025 年 11 月期间什么是真实的？&quot;）和冲突解决</li></ul><h2 id="设计目标" tabindex="-1"><a class="header-anchor" href="#设计目标">#</a> 设计目标</h2><ul><li><strong>离线</strong>：无需网络即可工作；可在笔记本电脑/Castle 上运行；无云依赖。</li><li><strong>可解释</strong>：检索的项目应该可归因（文件 + 位置）并与推理分离。</li><li><strong>低仪式感</strong>：每日日志保持 Markdown，无需繁重的 schema 工作。</li><li><strong>增量式</strong>：v1 仅使用 FTS 就很有用；语义/向量和图是可选升级。</li><li><strong>对智能体友好</strong>：使&quot;在 token 预算内回忆&quot;变得简单（返回小型事实包）。</li></ul><h2 id="北极星模型-hindsight-×-letta" tabindex="-1"><a class="header-anchor" href="#北极星模型-hindsight-×-letta">#</a> 北极星模型（Hindsight × Letta）</h2><p>需要融合两个部分：</p><ol><li><strong>Letta/MemGPT 风格的控制循环</strong></li></ol><ul><li>保持一个小的&quot;核心&quot;始终在上下文中（角色 + 关键用户事实）</li><li>其他所有内容都在上下文之外，通过工具检索</li><li>记忆写入是显式的工具调用（append/replace/insert），持久化后在下一轮重新注入</li></ul><ol start="2"><li><strong>Hindsight 风格的记忆基底</strong></li></ol><ul><li>分离观察到的、相信的和总结的内容</li><li>支持 retain/recall/reflect</li><li>带有置信度的观点可以随证据演变</li><li>实体感知检索 + 时间查询（即使没有完整的知识图谱）</li></ul><h2 id="提议的架构-markdown-数据源-派生索引" tabindex="-1"><a class="header-anchor" href="#提议的架构-markdown-数据源-派生索引">#</a> 提议的架构（Markdown 数据源 + 派生索引）</h2><h3 id="规范存储-git-友好" tabindex="-1"><a class="header-anchor" href="#规范存储-git-友好">#</a> 规范存储（git 友好）</h3><p>保持 <code>~/.opensoul/workspace</code> 作为规范的人类可读记忆。</p><p>建议的工作区布局：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.opensoul/workspace/</span></span>
<span class="line"><span>  memory.md                    # 小型：持久事实 + 偏好（类似核心）</span></span>
<span class="line"><span>  memory/</span></span>
<span class="line"><span>    YYYY-MM-DD.md              # 每日日志（追加；叙事）</span></span>
<span class="line"><span>  bank/                        # &quot;类型化&quot;记忆页面（稳定、可审查）</span></span>
<span class="line"><span>    world.md                   # 关于世界的客观事实</span></span>
<span class="line"><span>    experience.md              # 智能体做了什么（第一人称）</span></span>
<span class="line"><span>    opinions.md                # 主观偏好/判断 + 置信度 + 证据指针</span></span>
<span class="line"><span>    entities/</span></span>
<span class="line"><span>      Peter.md</span></span>
<span class="line"><span>      The-Castle.md</span></span>
<span class="line"><span>      warelay.md</span></span>
<span class="line"><span>      ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>注意：</p><ul><li><strong>每日日志保持为每日日志</strong>。无需将其转换为 JSON。</li><li><code>bank/</code> 文件是<strong>经过整理的</strong>，由反思任务生成，仍可手动编辑。</li><li><code>memory.md</code> 保持&quot;小型 + 类似核心&quot;：你希望 Clawd 每次会话都能看到的内容。</li></ul><h3 id="派生存储-机器回忆" tabindex="-1"><a class="header-anchor" href="#派生存储-机器回忆">#</a> 派生存储（机器回忆）</h3><p>在工作区下添加派生索引（不一定需要 git 跟踪）：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.opensoul/workspace/.memory/index.sqlite</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>后端支持：</p><ul><li>用于事实 + 实体链接 + 观点元数据的 SQLite schema</li><li>SQLite <strong>FTS5</strong> 用于词法回忆（快速、小巧、离线）</li><li>可选的嵌入表用于语义回忆（仍然离线）</li></ul><p>索引始终<strong>可从 Markdown 重建</strong>。</p><h2 id="retain-recall-reflect-操作循环" tabindex="-1"><a class="header-anchor" href="#retain-recall-reflect-操作循环">#</a> Retain / Recall / Reflect（操作循环）</h2><h3 id="retain-将每日日志规范化为-事实" tabindex="-1"><a class="header-anchor" href="#retain-将每日日志规范化为-事实">#</a> Retain：将每日日志规范化为&quot;事实&quot;</h3><p>Hindsight 在这里重要的关键洞察：存储<strong>叙事性、自包含的事实</strong>，而不是微小的片段。</p><p><code>memory/YYYY-MM-DD.md</code> 的实用规则：</p><ul><li>在一天结束时（或期间），添加一个 <code>## Retain</code> 部分，包含 2-5 个要点： <ul><li>叙事性（保留跨轮上下文）</li><li>自包含（独立时也有意义）</li><li>标记类型 + 实体提及</li></ul></li></ul><p>示例：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Retain</span></span>
<span class="line"><span>- W @Peter: Currently in Marrakech (Nov 27–Dec 1, 2025) for Andy&#39;s birthday.</span></span>
<span class="line"><span>- B @warelay: I fixed the Baileys WS crash by wrapping connection.update handlers in try/catch (see memory/2025-11-27.md).</span></span>
<span class="line"><span>- O(c=0.95) @Peter: Prefers concise replies (&amp;lt;1500 chars) on WhatsApp; long content goes into files.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>最小化解析：</p><ul><li>类型前缀：<code>W</code>（世界）、<code>B</code>（经历/传记）、<code>O</code>（观点）、<code>S</code>（观察/摘要；通常是生成的）</li><li>实体：<code>@Peter</code>、<code>@warelay</code> 等（slug 映射到 <code>bank/entities/*.md</code>）</li><li>观点置信度：<code>O(c=0.0..1.0)</code> 可选</li></ul><p>如果你不想让作者考虑这些：反思任务可以从日志的其余部分推断这些要点，但有一个显式的 <code>## Retain</code> 部分是最简单的&quot;质量杠杆&quot;。</p><h3 id="recall-对派生索引的查询" tabindex="-1"><a class="header-anchor" href="#recall-对派生索引的查询">#</a> Recall：对派生索引的查询</h3><p>Recall 应支持：</p><ul><li><strong>词法</strong>：&quot;查找精确的术语/名称/命令&quot;（FTS5）</li><li><strong>实体</strong>：&quot;告诉我关于 X 的信息&quot;（实体页面 + 实体链接的事实）</li><li><strong>时间</strong>：&quot;11 月 27 日前后发生了什么&quot;/&quot;自上周以来&quot;</li><li><strong>观点</strong>：&quot;Peter 偏好什么？&quot;（带置信度 + 证据）</li></ul><p>返回格式应对智能体友好并引用来源：</p><ul><li><code>kind</code>（<code>world|experience|opinion|observation</code>）</li><li><code>timestamp</code>（来源日期，或如果存在则提取的时间范围）</li><li><code>entities</code>（<code>[&quot;Peter&quot;,&quot;warelay&quot;]</code>）</li><li><code>content</code>（叙事性事实）</li><li><code>source</code>（<code>memory/2025-11-27.md#L12</code> 等）</li></ul><h3 id="reflect-生成稳定页面-更新信念" tabindex="-1"><a class="header-anchor" href="#reflect-生成稳定页面-更新信念">#</a> Reflect：生成稳定页面 + 更新信念</h3><p>反思是一个定时任务（每日或心跳 <code>ultrathink</code>），它：</p><ul><li>根据最近的事实更新 <code>bank/entities/*.md</code>（实体摘要）</li><li>根据强化/矛盾更新 <code>bank/opinions.md</code> 置信度</li><li>可选地提议对 <code>memory.md</code>（&quot;类似核心&quot;的持久事实）的编辑</li></ul><p>观点演变（简单、可解释）：</p><ul><li>每个观点有： <ul><li>陈述</li><li>置信度 <code>c ∈ [0,1]</code></li><li>last_updated</li><li>证据链接（支持 + 矛盾的事实 ID）</li></ul></li><li>当新事实到达时： <ul><li>通过实体重叠 + 相似性找到候选观点（先 FTS，后嵌入）</li><li>通过小幅增量更新置信度；大幅跳跃需要强矛盾 + 重复证据</li></ul></li></ul><h2 id="cli-集成-独立-vs-深度集成" tabindex="-1"><a class="header-anchor" href="#cli-集成-独立-vs-深度集成">#</a> CLI 集成：独立 vs 深度集成</h2><p>建议：<strong>深度集成到 OpenSoul</strong>，但保持可分离的核心库。</p><h3 id="为什么要集成到-opensoul" tabindex="-1"><a class="header-anchor" href="#为什么要集成到-opensoul">#</a> 为什么要集成到 OpenSoul？</h3><ul><li>OpenSoul 已经知道： <ul><li>工作区路径（<code>agents.defaults.workspace</code>）</li><li>会话模型 + 心跳</li><li>日志记录 + 故障排除模式</li></ul></li><li>你希望智能体自己调用工具： <ul><li><code>opensoul memory recall &quot;…&quot; --k 25 --since 30d</code></li><li><code>opensoul memory reflect --since 7d</code></li></ul></li></ul><h3 id="为什么仍要分离库" tabindex="-1"><a class="header-anchor" href="#为什么仍要分离库">#</a> 为什么仍要分离库？</h3><ul><li>保持记忆逻辑可测试，无需 Gateway 网关/运行时</li><li>可从其他上下文重用（本地脚本、未来的桌面应用等）</li></ul><p>形态： 记忆工具预计是一个小型 CLI + 库层，但这仅是探索性的。</p><h2 id="s-collide-suco-何时使用-研究" tabindex="-1"><a class="header-anchor" href="#s-collide-suco-何时使用-研究">#</a> &quot;S-Collide&quot; / SuCo：何时使用（研究）</h2><p>如果&quot;S-Collide&quot;指的是 <strong>SuCo（Subspace Collision）</strong>：这是一种 ANN 检索方法，通过在子空间中使用学习/结构化碰撞来实现强召回/延迟权衡（论文：arXiv 2411.14754，2024）。</p><p>对于 <code>~/.opensoul/workspace</code> 的务实观点：</p><ul><li><strong>不要从</strong> SuCo 开始。</li><li>从 SQLite FTS +（可选的）简单嵌入开始；你会立即获得大部分 UX 收益。</li><li>仅在以下情况下考虑 SuCo/HNSW/ScaNN 级别的解决方案： <ul><li>语料库很大（数万/数十万个块）</li><li>暴力嵌入搜索变得太慢</li><li>召回质量明显受到词法搜索的瓶颈限制</li></ul></li></ul><p>离线友好的替代方案（按复杂性递增）：</p><ul><li>SQLite FTS5 + 元数据过滤（零 ML）</li><li>嵌入 + 暴力搜索（如果块数量低，效果出奇地好）</li><li>HNSW 索引（常见、稳健；需要库绑定）</li><li>SuCo（研究级；如果有可嵌入的可靠实现则很有吸引力）</li></ul><p>开放问题：</p><ul><li>对于你的机器（笔记本 + 台式机）上的&quot;个人助理记忆&quot;，<strong>最佳</strong>的离线嵌入模型是什么？ <ul><li>如果你已经有 Ollama：使用本地模型嵌入；否则在工具链中附带一个小型嵌入模型。</li></ul></li></ul><h2 id="最小可用试点" tabindex="-1"><a class="header-anchor" href="#最小可用试点">#</a> 最小可用试点</h2><p>如果你想要一个最小但仍有用的版本：</p><ul><li>添加 <code>bank/</code> 实体页面和每日日志中的 <code>## Retain</code> 部分。</li><li>使用 SQLite FTS 进行带引用的回忆（路径 + 行号）。</li><li>仅在召回质量或规模需要时添加嵌入。</li></ul><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料">#</a> 参考资料</h2><ul><li>Letta / MemGPT 概念：&quot;核心记忆块&quot; + &quot;档案记忆&quot; + 工具驱动的自编辑记忆。</li><li>Hindsight 技术报告：&quot;retain / recall / reflect&quot;，四网络记忆，叙事性事实提取，观点置信度演变。</li><li>SuCo：arXiv 2411.14754（2024）：&quot;Subspace Collision&quot;近似最近邻检索。</li></ul>`,69)])])}const m=l(i,[["render",o]]);export{h as __pageData,m as default};
